import React from 'react'
import JumbotronImage from './JumbotronImage'
import MealsContainer from './MealsContainer';
import axios from 'axios';
import {useContext, useEffect, useState} from 'react';

const APIKEY = "c488888d957d42e8b5c88e4e7497b2e8";

function Home() {
  
    const [meals, setMeals] = useState([]);

  useEffect(() => {
    axios.get(`https://api.spoonacular.com/recipes/random?apiKey=${APIKEY}&number=5`)
    .then(({data}) => setMeals(data.recipes))

  }, []);

  console.log(meals[0]);

  return (
    <div>
        <JumbotronImage />
        
      <MealsContainer meals={meals}/>
    </div>
  )
}

export default Home
